import React, { useState, useEffect } from 'react';
import { Button, Space, Divider, Tooltip } from 'antd';
import { SaveOutlined, BoldOutlined, ItalicOutlined, UnorderedListOutlined, OrderedListOutlined, StrikethroughOutlined, FileMarkdownOutlined } from '@ant-design/icons';
import { Heading2, Quote, Code } from 'lucide-react';
import './NotesEditor.css';

/**
 * Notes Editor Component
 * Rich text editor for collaborative note-taking
 */
const NotesEditor = ({
  content,
  onSave,
  isConnected,
  activeUsers,
  typingUsers,
  isSaving
}) => {
  const [text, setText] = useState(content?.textContent || '');
  const [isEditing, setIsEditing] = useState(false);

  useEffect(() => {
    setText(content?.textContent || '');
  }, [content]);

  const handleChange = (e) => {
    setText(e.target.value);
    setIsEditing(true);
  };

  const handleSave = async () => {
    const updated = {
      ...content,
      textContent: text,
      contentType: 'TEXT'
    };

    await onSave(updated, `Updated notes`);
    setIsEditing(false);
  };

  const insertMarkdown = (before, after = '') => {
    const textarea = document.querySelector('.notes-editor textarea');
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const selectedText = text.substring(start, end);
    const newText = text.substring(0, start) + before + selectedText + after + text.substring(end);

    setText(newText);
    setIsEditing(true);

    // Move cursor
    setTimeout(() => {
      textarea.focus();
      textarea.selectionStart = start + before.length;
      textarea.selectionEnd = start + before.length + selectedText.length;
    }, 0);
  };

  const formatters = [
    {
      icon: <BoldOutlined />,
      title: 'Bold',
      action: () => insertMarkdown('**', '**'),
      shortcut: 'Ctrl+B'
    },
    {
      icon: <ItalicOutlined />,
      title: 'Italic',
      action: () => insertMarkdown('_', '_'),
      shortcut: 'Ctrl+I'
    },
    {
      icon: <StrikethroughOutlined />,
      title: 'Strikethrough',
      action: () => insertMarkdown('~~', '~~'),
      shortcut: 'Ctrl+Shift+X'
    },
    {
      icon: <Heading2 size={16} />,
      title: 'Heading',
      action: () => insertMarkdown('\n## ', '\n'),
      shortcut: 'Ctrl+Alt+1'
    },
    {
      icon: <UnorderedListOutlined />,
      title: 'Bullet List',
      action: () => insertMarkdown('\n- ', ''),
      shortcut: 'Ctrl+Shift+9'
    },
    {
      icon: <OrderedListOutlined />,
      title: 'Numbered List',
      action: () => insertMarkdown('\n1. ', ''),
      shortcut: 'Ctrl+Shift+0'
    },
    {
      icon: <Quote size={16} />,
      title: 'Quote',
      action: () => insertMarkdown('\n> ', '\n'),
      shortcut: 'Ctrl+Shift+B'
    },
    {
      icon: <Code size={16} />,
      title: 'Code Block',
      action: () => insertMarkdown('```\n', '\n```'),
      shortcut: 'Ctrl+Alt+C'
    }
  ];

  return (
    <div className="notes-editor-container">
      {/* Header with title */}
      <div className="notes-header">
        <div className="notes-header-left">
          <FileMarkdownOutlined className="notes-header-icon" />
          <h2 className="notes-title">Notes</h2>
        </div>
        <div className="notes-header-right">
          {isConnected && activeUsers && (
            <div className="active-users">
              <span className="user-dot"></span>
              <span className="user-count">{activeUsers.length} editing</span>
            </div>
          )}
        </div>
      </div>

      {/* Formatting toolbar - Notion style */}
      <div className="notes-toolbar">
        <div className="toolbar-group">
          {formatters.map((formatter, idx) => (
            <Tooltip key={idx} title={`${formatter.title} (${formatter.shortcut})`} placement="bottom">
              <button
                className="toolbar-btn"
                onClick={formatter.action}
                title={formatter.title}
              >
                {formatter.icon}
              </button>
            </Tooltip>
          ))}
        </div>

        <div className="toolbar-divider"></div>

        <Button
          type="primary"
          icon={<SaveOutlined />}
          loading={isSaving}
          disabled={!isEditing || !isConnected}
          onClick={handleSave}
          className="save-btn"
        >
          {isSaving ? 'Saving...' : 'Save'}
        </Button>
      </div>

      {/* Main editor textarea */}
      <textarea
        className="notes-editor"
        value={text}
        onChange={handleChange}
        placeholder="# Start typing...\n\nUse markdown formatting to style your notes. Type / for more options."
        spellCheck="true"
      />

      {/* Footer with stats */}
      <div className="notes-footer">
        <div className="notes-stats">
          <span className="stat-item">
            <span className="stat-label">Characters:</span>
            <span className="stat-value">{text.length.toLocaleString()}</span>
          </span>
          <span className="stat-divider">•</span>
          <span className="stat-item">
            <span className="stat-label">Words:</span>
            <span className="stat-value">{text.trim().split(/\s+/).filter(w => w).length}</span>
          </span>
          <span className="stat-divider">•</span>
          <span className="stat-item">
            <span className="stat-label">Lines:</span>
            <span className="stat-value">{text.split('\n').length}</span>
          </span>
        </div>

        <div className="notes-status">
          {isEditing && <span className="unsaved-indicator">● Unsaved changes</span>}
          {!isConnected && <span className="offline-indicator">🔌 Offline</span>}
        </div>
      </div>

      {/* Typing indicators */}
      {typingUsers && typingUsers.size > 0 && (
        <div className="typing-indicator">
          <span className="typing-user">
            {Array.from(typingUsers).slice(0, 2).join(', ')} {typingUsers.size > 1 ? 'are' : 'is'} typing...
          </span>
          <span className="typing-dots">
            <span></span>
            <span></span>
            <span></span>
          </span>
        </div>
      )}
    </div>
  );
};

export default NotesEditor;

import React, { useState, useRef, useEffect } from 'react';
import { Button, Space, Popover } from 'antd';
import { SaveOutlined, ClearOutlined, BgColorsOutlined, UndoOutlined, RedoOutlined } from '@ant-design/icons';
import './WhiteboardEditor.css';

/**
 * Whiteboard Editor Component
 * Free-form drawing canvas for collaborative sketching
 */
const WhiteboardEditor = ({
  content,
  onSave,
  isConnected,
  activeUsers,
  sendCursorMove,
  isSaving
}) => {
  const canvasRef = useRef(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [color, setColor] = useState('#0052cc');
  const [brushSize, setBrushSize] = useState(3);
  const [history, setHistory] = useState([]);
  const [historyStep, setHistoryStep] = useState(-1);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const context = canvas.getContext('2d');
    canvas.width = canvas.offsetWidth;
    canvas.height = canvas.offsetHeight;

    // Load drawing data
    if (content?.drawingData?.imageData) {
      const imageData = new ImageData(
        new Uint8ClampedArray(content.drawingData.imageData),
        canvas.width,
        canvas.height
      );
      context.putImageData(imageData, 0, 0);
    }

    // Initialize history
    setHistory([canvas.toDataURL()]);
    setHistoryStep(0);
  }, []);

  const getCanvasContext = () => {
    return canvasRef.current?.getContext('2d');
  };

  const startDrawing = (e) => {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    setIsDrawing(true);
    sendCursorMove(x, y, `drawing-${Date.now()}`, 'draw');

    const context = getCanvasContext();
    context.beginPath();
    context.moveTo(x, y);
    context.strokeStyle = color;
    context.lineWidth = brushSize;
    context.lineCap = 'round';
    context.lineJoin = 'round';
  };

  const draw = (e) => {
    if (!isDrawing) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    sendCursorMove(x, y, `drawing-${Date.now()}`, 'draw');

    const context = getCanvasContext();
    context.lineTo(x, y);
    context.stroke();
  };

  const stopDrawing = () => {
    if (!isDrawing) return;
    setIsDrawing(false);

    const canvas = canvasRef.current;
    const context = getCanvasContext();
    context.closePath();

    // Save to history
    const newHistory = history.slice(0, historyStep + 1);
    newHistory.push(canvas.toDataURL());
    setHistory(newHistory);
    setHistoryStep(newHistory.length - 1);
  };

  const handleClear = () => {
    const canvas = canvasRef.current;
    const context = getCanvasContext();
    context.clearRect(0, 0, canvas.width, canvas.height);

    const newHistory = history.slice(0, historyStep + 1);
    newHistory.push('');
    setHistory(newHistory);
    setHistoryStep(newHistory.length - 1);
  };

  const handleUndo = () => {
    if (historyStep > 0) {
      const newStep = historyStep - 1;
      setHistoryStep(newStep);
      redrawFromHistory(newStep);
    }
  };

  const handleRedo = () => {
    if (historyStep < history.length - 1) {
      const newStep = historyStep + 1;
      setHistoryStep(newStep);
      redrawFromHistory(newStep);
    }
  };

  const redrawFromHistory = (step) => {
    const canvas = canvasRef.current;
    const context = getCanvasContext();
    const img = new Image();

    img.onload = () => {
      context.clearRect(0, 0, canvas.width, canvas.height);
      if (img.src) {
        context.drawImage(img, 0, 0);
      }
    };

    img.src = history[step];
  };

  const handleSave = async () => {
    const canvas = canvasRef.current;
    const context = getCanvasContext();
    const imageData = context.getImageData(0, 0, canvas.width, canvas.height);

    const updated = {
      ...content,
      drawingData: {
        imageData: Array.from(imageData.data),
        width: canvas.width,
        height: canvas.height
      },
      contentType: 'WHITEBOARD'
    };

    await onSave(updated, 'Updated whiteboard drawing');
  };

  const colorOptions = ['#0052cc', '#ff5630', '#00875a', '#974f0c', '#5e4db2', '#ae2a19'];

  return (
    <div className="whiteboard-container">
      <div className="whiteboard-toolbar">
        <Space size="small">
          <Popover
            content={
              <div className="color-picker">
                {colorOptions.map(c => (
                  <button
                    key={c}
                    className={`color-option ${color === c ? 'active' : ''}`}
                    style={{ backgroundColor: c }}
                    onClick={() => setColor(c)}
                  />
                ))}
              </div>
            }
            trigger="click"
            placement="bottom"
          >
            <Button
              icon={<BgColorsOutlined />}
              style={{ backgroundColor: color, color: '#fff' }}
              size="small"
            >
              Color
            </Button>
          </Popover>

          <select
            value={brushSize}
            onChange={(e) => setBrushSize(parseInt(e.target.value))}
            className="brush-size-select"
          >
            <option value="1">1px</option>
            <option value="2">2px</option>
            <option value="3">3px (Normal)</option>
            <option value="5">5px</option>
            <option value="8">8px</option>
            <option value="12">12px</option>
          </select>
        </Space>

        <Space size="small">
          <Button
            size="small"
            icon={<UndoOutlined />}
            onClick={handleUndo}
            disabled={historyStep <= 0}
          />
          <Button
            size="small"
            icon={<RedoOutlined />}
            onClick={handleRedo}
            disabled={historyStep >= history.length - 1}
          />
          <Button
            size="small"
            danger
            icon={<ClearOutlined />}
            onClick={handleClear}
          >
            Clear
          </Button>
        </Space>

        <Space size="small">
          <Button
            type="primary"
            size="small"
            icon={<SaveOutlined />}
            loading={isSaving}
            disabled={!isConnected}
            onClick={handleSave}
          >
            Save
          </Button>
          {isConnected && (
            <span className="collaborators">👥 {activeUsers?.length || 0} drawing</span>
          )}
        </Space>
      </div>

      <canvas
        ref={canvasRef}
        className="whiteboard-canvas"
        onMouseDown={startDrawing}
        onMouseMove={draw}
        onMouseUp={stopDrawing}
        onMouseLeave={stopDrawing}
      />
    </div>
  );
};

export default WhiteboardEditor;

import { useState, useEffect } from 'react';
import { Select, Spin, Empty, Row, Col, Card, Statistic } from 'antd';
import { ClockCircleOutlined } from '@ant-design/icons';
import { DragDropContext, Droppable, Draggable } from '@hello-pangea/dnd';
import { useProject } from '../../context/ProjectContext';
import taskService from '../../services/taskService';
import './ScrumBoard.css';

/**
 * ScrumBoard - Sprint-based task board view
 * 
 * Features:
 * - Sprint selector dropdown
 * - Displays tasks only from selected sprint
 * - Drag-and-drop between status columns
 * - Sprint progress metrics
 * - Auto-defaults to active sprint
 * 
 * @component
 */
const ScrumBoard = () => {
    const { currentProject, sprints, activeSprint } = useProject();
    
    // State Management
    const [selectedSprint, setSelectedSprint] = useState(null);
    const [tasks, setTasks] = useState({});
    const [loading, setLoading] = useState(false);
    const [refreshTrigger] = useState(0);
    const [sprintMetrics, setSprintMetrics] = useState({
        total: 0,
        completed: 0,
        inProgress: 0,
        todo: 0,
    });

    // Board column configuration - reused from Kanban
    const COLUMNS = {
        'TODO': {
            name: 'To Do',
            color: '#626f86',
            bgColor: '#f8f9fa',
        },
        'IN_PROGRESS': {
            name: 'In Progress',
            color: '#0052cc',
            bgColor: '#f8f9fa',
        },
        'DONE': {
            name: 'Done',
            color: '#216e4e',
            bgColor: '#f8f9fa',
        },
    };

    /**
     * Initialize with active sprint
     */
    useEffect(() => {
        if (activeSprint) {
            setSelectedSprint(activeSprint._id);
        } else if (sprints.length > 0) {
            setSelectedSprint(sprints[0]._id);
        }
    }, [sprints, activeSprint]);

    /**
     * Load sprint tasks and calculate metrics
     */
    useEffect(() => {
        if (selectedSprint && currentProject) {
            loadSprintTasks();
        }
    }, [selectedSprint, currentProject, refreshTrigger]);

    /**
     * Reload when sprints data changes (when tasks are created/updated)
     */
    useEffect(() => {
        if (selectedSprint && sprints.length > 0) {
            // Auto-reload tasks when sprint data updates
            loadSprintTasks();
        }
    }, [sprints]);

    const loadSprintTasks = async () => {
        setLoading(true);
        try {
            // Fetch tasks for the selected sprint
            const sprintTasks = await taskService.getTasksBySprint(selectedSprint);
            
            // Group tasks by status
            const groupedTasks = {
                TODO: [],
                IN_PROGRESS: [],
                DONE: [],
            };

            sprintTasks.forEach(task => {
                const status = task.status?.toUpperCase() || 'TODO';
                if (groupedTasks[status]) {
                    groupedTasks[status].push(task);
                }
            });

            setTasks(groupedTasks);

            // Calculate metrics
            const completed = groupedTasks.DONE.length;
            const inProgress = groupedTasks.IN_PROGRESS.length;
            const todo = groupedTasks.TODO.length;
            const total = sprintTasks.length;

            setSprintMetrics({
                total,
                completed,
                inProgress,
                todo,
                completionRate: total > 0 ? Math.round((completed / total) * 100) : 0,
            });
        } catch (error) {
            console.error('Failed to load sprint tasks:', error);
        } finally {
            setLoading(false);
        }
    };

    /**
     * Handle task drag and drop
     */
    const handleDragEnd = async (result) => {
        const { source, destination, draggableId } = result;

        // No-op if dropped outside valid area
        if (!destination) return;

        // No-op if dropped in same position
        if (
            source.droppableId === destination.droppableId &&
            source.index === destination.index
        ) return;

        // Extract status from column ID
        const newStatus = destination.droppableId.toUpperCase();
        const taskId = draggableId;

        // Optimistic UI update
        const taskToMove = [
            ...tasks.TODO,
            ...tasks.IN_PROGRESS,
            ...tasks.DONE,
        ].find(t => t._id === taskId);

        if (taskToMove) {
            // Update local state
            const oldStatus = taskToMove.status.toUpperCase();
            setTasks(prev => ({
                ...prev,
                [oldStatus]: prev[oldStatus].filter(t => t._id !== taskId),
                [newStatus]: [
                    ...prev[newStatus],
                    { ...taskToMove, status: newStatus.toLowerCase() }
                ],
            }));

            // Update backend
            try {
                await taskService.updateTask(taskId, { 
                    status: newStatus.toLowerCase() 
                });
            } catch (error) {
                console.error('Failed to update task status:', error);
                // Reload to revert
                loadSprintTasks();
            }
        }
    };

    /**
     * Get selected sprint details
     */
    const getCurrentSprintDetails = () => {
        return sprints.find(s => s._id === selectedSprint);
    };

    if (loading && Object.values(tasks).every(col => col.length === 0)) {
        return <Spin size="large" style={{ display: 'flex', justifyContent: 'center', padding: '40px' }} />;
    }

    const currentSprint = getCurrentSprintDetails();

    return (
        <div className="scrum-board-container">
            {/* Sprint Header Section */}
            <div className="scrum-board-header">
                <div className="sprint-selector-section">
                    <label>Select Sprint:</label>
                    <Select
                        value={selectedSprint}
                        onChange={setSelectedSprint}
                        style={{ width: 250 }}
                        placeholder="Select a sprint"
                        options={sprints.map(sprint => ({
                            label: `${sprint.name} (${sprint.status})`,
                            value: sprint._id,
                        }))}
                    />
                </div>

                {currentSprint && (
                    <div className="sprint-details">
                        <span className="sprint-name">{currentSprint.name}</span>
                        <span className={`sprint-status status-${currentSprint.status.toLowerCase()}`}>
                            {currentSprint.status}
                        </span>
                    </div>
                )}
            </div>

            {/* Sprint Metrics */}
            {currentSprint && (
                <Card className="sprint-metrics-card">
                    <Row gutter={[24, 0]}>
                        <Col xs={24} sm={12} md={6}>
                            <Statistic
                                title="Total Tasks"
                                value={sprintMetrics.total}
                                prefix={<ClockCircleOutlined />}
                            />
                        </Col>
                        <Col xs={24} sm={12} md={6}>
                            <Statistic
                                title="To Do"
                                value={sprintMetrics.todo}
                                valueStyle={{ color: '#626f86' }}
                            />
                        </Col>
                        <Col xs={24} sm={12} md={6}>
                            <Statistic
                                title="In Progress"
                                value={sprintMetrics.inProgress}
                                valueStyle={{ color: '#0052cc' }}
                            />
                        </Col>
                        <Col xs={24} sm={12} md={6}>
                            <Statistic
                                title="Completed"
                                value={sprintMetrics.completed}
                                suffix={`/ ${sprintMetrics.total}`}
                                valueStyle={{ color: '#216e4e' }}
                            />
                        </Col>
                    </Row>
                </Card>
            )}

            {/* Scrum Board */}
            {sprintMetrics.total === 0 ? (
                <Empty
                    description="No tasks in this sprint"
                    style={{ marginTop: 40 }}
                />
            ) : (
                <DragDropContext onDragEnd={handleDragEnd}>
                    <div className="scrum-board">
                        {Object.entries(COLUMNS).map(([statusKey, columnConfig]) => (
                            <Droppable key={statusKey} droppableId={statusKey}>
                                {(provided, snapshot) => (
                                    <div
                                        className={`scrum-column ${snapshot.isDraggingOver ? 'dragging-over' : ''}`}
                                        ref={provided.innerRef}
                                        {...provided.droppableProps}
                                        style={{
                                            backgroundColor: snapshot.isDraggingOver ? '#deebff' : columnConfig.bgColor,
                                            ...provided.droppableProps.style,
                                        }}
                                    >
                                        {/* Column Header */}
                                        <div className="scrum-column-header">
                                            <div className="column-title">
                                                <span
                                                    className="column-dot"
                                                    style={{ backgroundColor: columnConfig.color }}
                                                />
                                                <span className="column-name">{columnConfig.name}</span>
                                            </div>
                                            <span className="column-count">
                                                {tasks[statusKey]?.length || 0}
                                            </span>
                                        </div>

                                        {/* Tasks */}
                                        <div className="scrum-tasks">
                                            {(tasks[statusKey] || []).map((task, index) => (
                                                <Draggable
                                                    key={task._id}
                                                    draggableId={task._id}
                                                    index={index}
                                                >
                                                    {(provided, snapshot) => (
                                                        <div
                                                            ref={provided.innerRef}
                                                            {...provided.draggableProps}
                                                            {...provided.dragHandleProps}
                                                            className={`scrum-card ${snapshot.isDragging ? 'dragging' : ''}`}
                                                        >
                                                            {/* Task Key */}
                                                            <div className="scrum-card-key">
                                                                <span className="task-key-badge" style={{ backgroundColor: columnConfig.color }}>
                                                                    {task.key || `TASK-${task._id.slice(0, 6)}`}
                                                                </span>
                                                            </div>

                                                            {/* Task Title */}
                                                            <div className="scrum-card-title">
                                                                {task.title}
                                                            </div>

                                                            {/* Task Metadata */}
                                                            <div className="scrum-card-footer">
                                                                {task.priority && (
                                                                    <span className={`priority-badge priority-${task.priority.toLowerCase()}`}>
                                                                        {task.priority}
                                                                    </span>
                                                                )}
                                                                {task.assignee && (
                                                                    <span className="assignee">
                                                                        {task.assignee.name?.split(' ')[0]}
                                                                    </span>
                                                                )}
                                                            </div>
                                                        </div>
                                                    )}
                                                </Draggable>
                                            ))}
                                            {provided.placeholder}
                                        </div>
                                    </div>
                                )}
                            </Droppable>
                        ))}
                    </div>
                </DragDropContext>
            )}
        </div>
    );
};

export default ScrumBoard;

import { useState, useEffect } from 'react';
import { DragDropContext, Droppable, Draggable } from '@hello-pangea/dnd';
import { Card, Typography, Tag, Avatar, Space, Button, Empty, message, Select, Segmented, Grid, Tooltip, Input, Progress, Dropdown, Badge } from 'antd';
import { ClockCircleOutlined, FilterOutlined, DownloadOutlined, PlusOutlined } from '@ant-design/icons';
import { useProject } from '../../context/ProjectContext';
import taskService from '../../services/taskService';
import IssueDetailDrawer from '../work/IssueDetailDrawer';
import CreateIssueModal from './CreateIssueModal';
import './TaskBoard.css';

const { Text, Title } = Typography;

const COLUMNS = {
    'todo': { title: 'Backlog', status: 'todo', color: '#f8f9fa', headerColor: '#626f86', bgColor: '#fafbfc' },
    'in_progress': { title: 'In Progress', status: 'in_progress', color: '#f8f9fa', headerColor: '#0052cc', bgColor: '#deebff' },
    'review': { title: 'In Review', status: 'review', color: '#f8f9fa', headerColor: '#ae2a19', bgColor: '#ffeceb' },
    'done': { title: 'Done', status: 'done', color: '#f8f9fa', headerColor: '#216e4e', bgColor: '#dffcf0' }
};

const TaskBoard = () => {
    const { currentProject, activeSprint } = useProject();
    const [selectedIssue, setSelectedIssue] = useState(null);
    const [boardData, setBoardData] = useState({});
    const [searchFilter, setSearchFilter] = useState('');
    const [priorityFilter, setPriorityFilter] = useState('all');

    // Mobile View State
    const screens = Grid.useBreakpoint();
    const isMobile = !screens.md;
    const [mobileStatusFilter, setMobileStatusFilter] = useState('todo');
    const [createModalOpen, setCreateModalOpen] = useState(false);

    useEffect(() => {
        if (currentProject && activeSprint) {
            loadSprintIssues();
        } else {
            setBoardData({});
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [currentProject, activeSprint]);

    const loadSprintIssues = async () => {
        try {
            const data = await taskService.getTasks({
                projectId: currentProject._id,
                sprintId: activeSprint._id
            });
            groupIssuesByStatus(data);
        } catch (error) {
            console.error("Failed to load board issues", error);
        }
    };

    const groupIssuesByStatus = (taskList) => {
        const grouped = {
            'todo': [],
            'in_progress': [],
            'review': [],
            'done': []
        };

        taskList.forEach(task => {
            const status = task.status || 'todo';
            if (grouped[status]) {
                grouped[status].push(task);
            } else {
                grouped['todo'].push(task);
            }
        });
        setBoardData(grouped);
    };

    const getFilteredIssues = (columnIssues) => {
        return columnIssues.filter(issue => {
            const matchesSearch = issue.title.toLowerCase().includes(searchFilter.toLowerCase()) ||
                                 issue.key.toLowerCase().includes(searchFilter.toLowerCase());
            const matchesPriority = priorityFilter === 'all' || issue.priority === priorityFilter;
            return matchesSearch && matchesPriority;
        });
    };



    const getProgressPercentage = () => {
        const total = Object.values(boardData).flat().length;
        const done = boardData['done']?.length || 0;
        return total === 0 ? 0 : Math.round((done / total) * 100);
    };

    const handleDragEnd = async (result) => {
        const { destination, source, draggableId } = result;

        if (!destination) return;
        if (
            destination.droppableId === source.droppableId &&
            destination.index === source.index
        ) return;

        const startStatus = source.droppableId;
        const finishStatus = destination.droppableId;

        // Optimistic UI Update
        const newBoardData = { ...boardData };

        // Remove from source
        const [movedIssue] = newBoardData[startStatus].splice(source.index, 1);
        // Add to destination
        newBoardData[finishStatus].splice(destination.index, 0, movedIssue);

        setBoardData(newBoardData);

        // API Call
        try {
            await taskService.updateTask(draggableId, { status: finishStatus });
            message.success(`Task moved to ${COLUMNS[finishStatus].title}`);
        } catch (error) {
            console.error('Failed to update task status:', error);
            const errorMsg = error.response?.data?.message || error.message || 'Failed to update status';
            message.error(errorMsg);
            loadSprintIssues(); // Revert
        }
    };

    if (!currentProject) return <Empty description="Select a Project" />;
    if (!activeSprint) return <Empty description="No Active Sprint" />;

    return (
        <div className="kanban-board-container">
            {/* Header Section */}
            <div className="kanban-header">
                <div className="header-left">
                    <div className="header-title-section">
                        <Title level={2} style={{ marginBottom: 4, marginTop: 0 }}>
                            {currentProject.name}
                        </Title>
                        <div className="header-breadcrumb">
                            <Text type="secondary">{activeSprint.name} • Board</Text>
                        </div>
                    </div>
                </div>
                {!isMobile && (
                    <div className="header-right">
                        <span className="task-count-badge">
                            <Text type="secondary">{Object.values(boardData).flat().length} issues</Text>
                        </span>
                    </div>
                )}
            </div>

            {/* Filters Section */}
            <div className="kanban-filters">
                <Input.Search
                    placeholder="Search board"
                    style={{ width: 250 }}
                    value={searchFilter}
                    onChange={(e) => setSearchFilter(e.target.value)}
                    allowClear
                />
                <Select
                    placeholder="Epic"
                    style={{ width: 150 }}
                    options={[
                        { value: 'all', label: 'All Epics' },
                        { value: 'frontend', label: 'Frontend' },
                        { value: 'backend', label: 'Backend' }
                    ]}
                />
                <Select
                    placeholder="Type"
                    style={{ width: 120 }}
                    options={[
                        { value: 'all', label: 'All Types' },
                        { value: 'task', label: 'Task' },
                        { value: 'bug', label: 'Bug' },
                        { value: 'feature', label: 'Feature' }
                    ]}
                />
                <Dropdown
                    menu={{
                        items: [
                            { key: 'all', label: 'All' },
                            { key: 'high', label: 'High Priority' },
                            { key: 'medium', label: 'Medium Priority' },
                            { key: 'low', label: 'Low Priority' }
                        ],
                        onClick: (e) => setPriorityFilter(e.key)
                    }}
                >
                    <Button icon={<FilterOutlined />}>Quick filters</Button>
                </Dropdown>
                <div style={{ marginLeft: 'auto' }}>
                    <Button 
                        type="primary" 
                        icon={<PlusOutlined />}
                        onClick={() => setCreateModalOpen(true)}
                    >
                        Create Issue
                    </Button>
                </div>
            </div>

            {isMobile ? (
                // MOBILE VIEW
                <div className="kanban-mobile">
                    <Segmented
                        block
                        options={Object.keys(COLUMNS).map(key => ({
                            label: `${COLUMNS[key].title} (${getFilteredIssues(boardData[key] || []).length})`,
                            value: key
                        }))}
                        value={mobileStatusFilter}
                        onChange={setMobileStatusFilter}
                    />

                    <div className="mobile-tasks-container">
                        {getFilteredIssues(boardData[mobileStatusFilter] || []).map(issue => (
                            <KanbanCard
                                key={issue._id}
                                issue={issue}
                                onClick={() => setSelectedIssue(issue)}
                            />
                        ))}
                        {getFilteredIssues(boardData[mobileStatusFilter] || []).length === 0 && (
                            <Empty image={Empty.PRESENTED_IMAGE_SIMPLE} description="No tasks" />
                        )}
                    </div>
                </div>
            ) : (
                // DESKTOP VIEW: Kanban Columns
                <DragDropContext onDragEnd={handleDragEnd}>
                    <div className="kanban-board">
                        {Object.keys(COLUMNS).map(columnId => {
                            const filteredIssues = getFilteredIssues(boardData[columnId] || []);
                            return (
                                <div key={columnId} className="kanban-column">
                                    {/* Column Header */}
                                    <div
                                        className="column-header"
                                        style={{ borderTopColor: COLUMNS[columnId].headerColor }}
                                    >
                                        <div className="column-title">
                                            <span className="column-name">{COLUMNS[columnId].title}</span>
                                            <Badge 
                                                count={filteredIssues.length} 
                                                style={{ backgroundColor: COLUMNS[columnId].headerColor }}
                                            />
                                        </div>
                                    </div>

                                    {/* Tasks Container */}
                                    <Droppable droppableId={columnId}>
                                        {(provided, snapshot) => (
                                            <div
                                                {...provided.droppableProps}
                                                ref={provided.innerRef}
                                                className={`column-tasks ${snapshot.isDraggingOver ? 'dragging-over' : ''}`}
                                                style={{
                                                    backgroundColor: COLUMNS[columnId].color,
                                                }}
                                            >
                                                {filteredIssues.map((issue, index) => (
                                                    <Draggable
                                                        key={issue._id}
                                                        draggableId={issue._id}
                                                        index={index}
                                                    >
                                                        {(provided, snapshot) => (
                                                            <div
                                                                ref={provided.innerRef}
                                                                {...provided.draggableProps}
                                                                {...provided.dragHandleProps}
                                                                onClick={() => setSelectedIssue(issue)}
                                                            >
                                                                <KanbanCard
                                                                    issue={issue}
                                                                    isDragging={snapshot.isDragging}
                                                                />
                                                            </div>
                                                        )}
                                                    </Draggable>
                                                ))}
                                                {provided.placeholder}
                                                {filteredIssues.length === 0 && (
                                                    <div className="empty-column">
                                                        <Text type="secondary">No tasks</Text>
                                                    </div>
                                                )}
                                            </div>
                                        )}
                                    </Droppable>
                                </div>
                            );
                        })}
                    </div>
                </DragDropContext>
            )}

            <IssueDetailDrawer
                open={!!selectedIssue}
                issue={selectedIssue}
                onClose={() => {
                    setSelectedIssue(null);
                    loadSprintIssues();
                }}
            />

            <CreateIssueModal 
                open={createModalOpen} 
                onClose={() => setCreateModalOpen(false)}
                onIssueCreated={() => {
                    loadSprintIssues();
                    setCreateModalOpen(false);
                }}
            />
        </div>
    );
};

// Kanban Card Component
const KanbanCard = ({ issue, isDragging }) => {
    const isOverdue = issue.dueDate && new Date(issue.dueDate) < new Date();

    // Generate random color for the task key based on the issue ID
    const colors = ['#FF6B6B', '#4ECDC4', '#45B7D1', '#96CEB4', '#FFEAA7', '#DDA0DD', '#87CEEB'];
    const colorIndex = (issue._id?.charCodeAt(0) || 0) % colors.length;
    const keyColor = colors[colorIndex];

    return (
        <div
            className={`kanban-card ${isDragging ? 'dragging' : ''}`}
            style={{
                boxShadow: isDragging ? '0 5px 15px rgba(0,0,0,0.3)' : '0 1px 3px rgba(0,0,0,0.12)',
            }}
        >
            {/* Card Key */}
            <div className="card-key">
                <span className="key-badge" style={{ backgroundColor: keyColor }}>
                    {issue.key || `TASK-${issue._id?.slice(-4).toUpperCase()}`}
                </span>
            </div>

            {/* Card Title */}
            <div className="card-title">
                <Text ellipsis={{ rows: 2, tooltip: true }} style={{ fontSize: 13, fontWeight: 500, color: '#262626' }}>
                    {issue.title}
                </Text>
            </div>

            {/* Card Labels/Tags */}
            {issue.labels && issue.labels.length > 0 && (
                <div className="card-labels">
                    {issue.labels.slice(0, 2).map((label, idx) => (
                        <Tag 
                            key={idx} 
                            style={{ 
                                fontSize: 10, 
                                backgroundColor: '#DCDCDC', 
                                color: '#262626',
                                border: 'none'
                            }}
                        >
                            {label}
                        </Tag>
                    ))}
                    {issue.labels.length > 2 && (
                        <Tag style={{ fontSize: 10 }}>+{issue.labels.length - 2}</Tag>
                    )}
                </div>
            )}

            {/* Card Footer */}
            <div className="card-footer">
                <div className="footer-left">
                    {issue.dueDate && (
                        <Tooltip title={`Due: ${new Date(issue.dueDate).toLocaleDateString()}`}>
                            <Tag
                                icon={<ClockCircleOutlined />}
                                color={isOverdue ? 'error' : 'default'}
                                style={{ fontSize: 10, margin: 0, marginRight: 4 }}
                            >
                                {new Date(issue.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                            </Tag>
                        </Tooltip>
                    )}
                </div>
                <div className="footer-right">
                    {issue.assignedTo && issue.assignedTo.length > 0 && (
                        <Tooltip title={issue.assignedTo.map(u => u.fullName || u.name).join(', ')}>
                            <Avatar.Group maxCount={2} size="small" style={{ marginLeft: 8 }}>
                                {issue.assignedTo.map(assignee => (
                                    <Avatar
                                        key={assignee._id}
                                        size="small"
                                        style={{ 
                                            backgroundColor: keyColor,
                                            fontSize: 10
                                        }}
                                    >
                                        {(assignee.fullName || assignee.name || 'U')?.[0]?.toUpperCase()}
                                    </Avatar>
                                ))}
                            </Avatar.Group>
                        </Tooltip>
                    )}
                </div>
            </div>
        </div>
    );
};

export default TaskBoard;

