import React, { useState, useEffect } from 'react';
import { Clock, Play, Pause, X } from 'lucide-react';
import { useTimerContext } from '../../context/TimerContext';
import './WorkLogs.css';

/**
 * TimerWidget
 * Floating timer widget that displays running timer across the app
 * Shows work item being timed and elapsed time
 */
const TimerWidget = () => {
  const { runningTimer, stopTimer, pauseTimer } = useTimerContext();
  const [elapsedTime, setElapsedTime] = useState('00:00:00');
  const [showWidget, setShowWidget] = useState(false);

  // Update elapsed time every second
  useEffect(() => {
    if (!runningTimer) {
      setShowWidget(false);
      return;
    }

    setShowWidget(true);

    const interval = setInterval(() => {
      const start = new Date(runningTimer.startTime);
      const now = new Date();
      const elapsed = Math.floor((now - start) / 1000);

      const hours = Math.floor(elapsed / 3600);
      const minutes = Math.floor((elapsed % 3600) / 60);
      const seconds = elapsed % 60;

      setElapsedTime(
        `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`
      );
    }, 1000);

    return () => clearInterval(interval);
  }, [runningTimer]);

  const handleStop = async () => {
    try {
      await stopTimer(runningTimer.workItemId);
    } catch (error) {
      console.error('Failed to stop timer:', error);
    }
  };

  const handlePause = async () => {
    try {
      await pauseTimer();
    } catch (error) {
      console.error('Failed to pause timer:', error);
    }
  };

  if (!showWidget || !runningTimer) return null;

  // Get work item title (might be in the object or need to fetch)
  const workItemTitle = runningTimer.workItemId?.title || 'Work Item';

  return (
    <div className="timer-widget">
      <div className="timer-widget-header">
        <div className="timer-widget-title">
          <Clock size={16} style={{ display: 'inline', marginRight: '6px' }} />
          {workItemTitle}
        </div>
      </div>

      <div className="timer-widget-time timer-pulse">
        {elapsedTime}
      </div>

      <div className="timer-widget-controls">
        <button
          className="timer-widget-btn primary"
          onClick={handlePause}
          title="Pause and switch task"
        >
          <Pause size={14} />
          Switch
        </button>
        <button
          className="timer-widget-btn danger"
          onClick={handleStop}
          title="Stop timer"
        >
          <X size={14} />
          Stop
        </button>
      </div>
    </div>
  );
};

export default TimerWidget;

import React, { useState, useEffect } from 'react';
import { Clock, Plus, AlertCircle } from 'lucide-react';
import { useTimerContext } from '../../context/TimerContext';
import workLogService from '../../services/workLogService';
import WorkLogList from './WorkLogList';
import LogWorkModal from './LogWorkModal';
import './WorkLogs.css';

/**
 * WorkLogPanel
 * Main component for work logging on a ticket
 * Displays timer controls, work log list, and manual entry modal
 */
const WorkLogPanel = ({ workItemId, onTimeUpdated }) => {
  const { runningTimer, startTimer, stopTimer, isTimerRunning, currentWorkItemId } = useTimerContext();
  const [workLogs, setWorkLogs] = useState([]);
  const [timeSummary, setTimeSummary] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showManualModal, setShowManualModal] = useState(false);
  const [isStartingTimer, setIsStartingTimer] = useState(false);

  // Load work logs and summary
  const loadWorkLogs = async () => {
    try {
      setLoading(true);
      setError(null);

      const [logsRes, summaryRes] = await Promise.all([
        workLogService.getWorkLogs(workItemId),
        workLogService.getTimeSummary(workItemId)
      ]);

      setWorkLogs(logsRes.data || []);
      setTimeSummary(summaryRes.data || {});

      if (onTimeUpdated) {
        onTimeUpdated(summaryRes.data);
      }
    } catch (err) {
      setError(err.message);
      console.error('Failed to load work logs:', err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadWorkLogs();

    // Refresh every 10 seconds if timer is running
    if (isTimerRunning && currentWorkItemId === workItemId) {
      const interval = setInterval(loadWorkLogs, 10000);
      return () => clearInterval(interval);
    }
  }, [workItemId, isTimerRunning, currentWorkItemId]);

  const handleStartTimer = async () => {
    try {
      setIsStartingTimer(true);
      await startTimer(workItemId, `Work on ${workItemId}`);
      // Refresh logs after short delay to see the new timer
      setTimeout(loadWorkLogs, 500);
    } catch (err) {
      setError('Failed to start timer');
      console.error(err);
    } finally {
      setIsStartingTimer(false);
    }
  };

  const handleStopTimer = async () => {
    try {
      await stopTimer(workItemId);
      // Refresh logs to see the completed timer
      setTimeout(loadWorkLogs, 500);
    } catch (err) {
      setError('Failed to stop timer');
      console.error(err);
    }
  };

  const handleManualLogCreated = async () => {
    setShowManualModal(false);
    await loadWorkLogs();
  };

  const handleLogDeleted = async () => {
    await loadWorkLogs();
  };

  const isTimerActiveOnThisItem = runningTimer && currentWorkItemId === workItemId;

  return (
    <div className="work-log-panel">
      <h3 className="work-log-panel-title">
        <Clock size={18} />
        Time Logging
      </h3>

      {error && (
        <div style={{
          background: '#fee2e2',
          border: '1px solid #fecaca',
          color: '#991b1b',
          padding: '12px',
          borderRadius: '6px',
          marginBottom: '12px',
          display: 'flex',
          gap: '8px',
          alignItems: 'center'
        }}>
          <AlertCircle size={16} />
          {error}
        </div>
      )}

      {/* Timer Controls */}
      <div className="work-log-actions">
        {!isTimerActiveOnThisItem ? (
          <button
            className="work-log-btn start-timer"
            onClick={handleStartTimer}
            disabled={isStartingTimer || (isTimerRunning && currentWorkItemId !== workItemId)}
          >
            {isStartingTimer ? '⏳ Starting...' : '▶ Start Timer'}
          </button>
        ) : (
          <button
            className="work-log-btn stop-timer"
            onClick={handleStopTimer}
          >
            ⏹ Stop Timer
          </button>
        )}

        <button
          className="work-log-btn manual"
          onClick={() => setShowManualModal(true)}
        >
          <Plus size={16} />
          Log Time Manually
        </button>
      </div>

      {/* Time Summary */}
      {timeSummary && timeSummary.totalHours > 0 && (
        <div className="time-summary">
          <div className="time-summary-title">Time Logged</div>
          <div className="time-summary-stats">
            <div className="time-summary-stat">
              <div className="time-summary-stat-label">Total Time</div>
              <div className="time-summary-stat-value">
                {timeSummary.totalHours}h
              </div>
            </div>
            <div className="time-summary-stat">
              <div className="time-summary-stat-label">Entries</div>
              <div className="time-summary-stat-value">
                {timeSummary.logCount}
              </div>
            </div>
            {timeSummary.billableHours !== timeSummary.totalHours && (
              <div className="time-summary-stat">
                <div className="time-summary-stat-label">Billable</div>
                <div className="time-summary-stat-value">
                  {timeSummary.billableHours}h
                </div>
              </div>
            )}
          </div>

          {/* User breakdown */}
          {timeSummary.byUser && timeSummary.byUser.length > 0 && (
            <div className="time-summary-by-user">
              <div className="time-summary-by-user-title">By User</div>
              {timeSummary.byUser.map((user) => (
                <div key={user.userId} className="time-summary-user-item">
                  <span className="time-summary-user-name">{user.userName}</span>
                  <span className="time-summary-user-time">
                    {Math.round((user.totalMinutes / 60) * 10) / 10}h
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Work Log List */}
      {!loading && workLogs.length > 0 && (
        <WorkLogList
          logs={workLogs}
          onDeleted={handleLogDeleted}
        />
      )}

      {!loading && workLogs.length === 0 && !timeSummary?.totalHours && (
        <div style={{
          textAlign: 'center',
          padding: '24px',
          color: '#6b7280',
          fontSize: '14px'
        }}>
          No work logs yet. Start by clicking "Start Timer" or logging time manually.
        </div>
      )}

      {loading && (
        <div style={{
          textAlign: 'center',
          padding: '24px',
          color: '#6b7280'
        }}>
          ⏳ Loading work logs...
        </div>
      )}

      {/* Manual Log Modal */}
      {showManualModal && (
        <LogWorkModal
          workItemId={workItemId}
          onClose={() => setShowManualModal(false)}
          onCreated={handleManualLogCreated}
        />
      )}
    </div>
  );
};

export default WorkLogPanel;

import { Drawer, Typography, Descriptions, Tag, Space, Avatar, Divider, Tabs, Button, Input, List, message, Select, Grid, Card, Timeline, Tooltip, Empty, Popconfirm, Spin, Modal } from 'antd';
import {
    CloseOutlined,
    LinkOutlined,
    PaperClipOutlined,
    ShareAltOutlined,
    MoreOutlined,
    ClockCircleOutlined,
    BulbOutlined,
    CalendarOutlined,
    BranchesOutlined,
    DeleteOutlined,
    ExclamationCircleOutlined,
    LoadingOutlined,
    CheckOutlined,
    RobotOutlined
} from '@ant-design/icons';
import { useState, useEffect, useRef } from 'react';
import taskService from '../../services/taskService';
import userService from '../../services/userService';
import { useAuth } from '../../context/AuthContext';
import SubTaskPanel from '../SubTaskPanel';
import WorkLogPanel from '../work-logs/WorkLogPanel';

const { Title, Text, Paragraph } = Typography;
const { TextArea } = Input;
const { useBreakpoint } = Grid;

/**
 * ============================================================================
 * WORKFLOW VALIDATION & RULES
 * ============================================================================
 * Defines allowed status transitions for Jira-like workflow
 */
const WORKFLOW_RULES = {
    'todo': ['in_progress'],
    'in_progress': ['review', 'todo'],
    'review': ['in_progress', 'done'],
    'done': ['in_progress'] // Allow reopening
};

/**
 * Validates if a status transition is allowed
 */
const isValidStatusTransition = (currentStatus, newStatus) => {
    if (currentStatus === newStatus) return true;
    return WORKFLOW_RULES[currentStatus]?.includes(newStatus) || false;
};

/**
 * Formats relative time (e.g., "2 minutes ago")
 */
const formatRelativeTime = (date) => {
    if (!date) return 'unknown';
    const now = new Date();
    const then = new Date(date);
    const diffMs = now - then;
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return 'just now';
    if (diffMins < 60) return `${diffMins} minute${diffMins > 1 ? 's' : ''} ago`;
    if (diffHours < 24) return `${diffHours} hour${diffHours > 1 ? 's' : ''} ago`;
    if (diffDays < 7) return `${diffDays} day${diffDays > 1 ? 's' : ''} ago`;
    return then.toLocaleDateString();
};

const IssueDetailDrawer = ({ open, onClose, issue }) => {
    const { user } = useAuth();
    const [currentIssue, setCurrentIssue] = useState(issue);
    const [comment, setComment] = useState('');
    const [sending, setSending] = useState(false);
    const [users, setUsers] = useState([]);
    const screens = useBreakpoint();
    const isMobile = !screens.sm;
    const originalIssueRef = useRef(issue);

    useEffect(() => {
        setCurrentIssue(issue);
        originalIssueRef.current = issue;
    }, [issue]);

    useEffect(() => {
        if (open) {
            fetchUsers();
        }
    }, [open]);

    const fetchUsers = async () => {
        try {
            const data = await userService.getUsers();
            setUsers(data);
        } catch (error) {
            console.error('Failed to fetch users:', error);
        }
    };

    if (!currentIssue) return null;

    /**
     * ========================================================================
     * OPTIMISTIC UI UPDATE - Inline Editing
     * ========================================================================
     * 1. Update local state immediately (optimistic)
     * 2. Call API in background
     * 3. If API fails, revert to original state
     */
    const handleUpdate = async (field, value) => {
        // Validate workflow rules for status changes
        if (field === 'status') {
            if (!isValidStatusTransition(currentIssue.status, value)) {
                message.warning(`Cannot transition from ${currentIssue.status} to ${value}`);
                return;
            }
        }

        // Save original state for rollback
        const originalValue = currentIssue[field];
        
        // Optimistic update: update UI immediately
        setCurrentIssue(prev => ({
            ...prev,
            [field]: value,
            updatedAt: new Date().toISOString() // Update timestamp
        }));

        setLoadingField(field);

        try {
            // API call in background
            const updated = await taskService.updateTask(currentIssue._id, { 
                [field]: value 
            });
            
            // Sync with server response
            setCurrentIssue(updated);
            message.success(`${field} updated`);
        } catch (error) {
            // Rollback on error
            setCurrentIssue(prev => ({
                ...prev,
                [field]: originalValue,
                updatedAt: originalIssueRef.current.updatedAt
            }));
            message.error(`Failed to update ${field}`);
            console.error('Update error:', error);
        } finally {
            setLoadingField(null);
        }
    };

    /**
     * ========================================================================
     * COMMENTS - Simple Text-based
     * ========================================================================
     * User types comment → Submit → Append to issue.comments → Display
     * No threading, no reactions, no edit (MVP)
     */
    const handleAddComment = async () => {
        if (!comment.trim()) return;
        
        setSending(true);
        try {
            // Call API to add comment
            const updated = await taskService.addComment(currentIssue._id, {
                text: comment.trim(),
                user: user._id
            });

            // Update UI with new comments
            setCurrentIssue(prev => ({
                ...prev,
                comments: updated.comments || [
                    ...prev.comments || [],
                    {
                        _id: Date.now(),
                        text: comment,
                        user: user,
                        timestamp: new Date().toISOString()
                    }
                ],
                updatedAt: new Date().toISOString()
            }));

            setComment('');
            message.success('Comment added');
        } catch (error) {
            console.error('Failed to add comment:', error);
            message.error('Failed to add comment');
        } finally {
            setSending(false);
        }
    };



    // Delete handler - only for creator or admin
    const canDelete = user?.role === 'admin' ||
        currentIssue.assignedBy?._id === user?._id ||
        currentIssue.assignedBy === user?._id;

    const handleDelete = async () => {
        try {
            await taskService.deleteTask(currentIssue._id);
            message.success('Task deleted');
            onClose();
        } catch (error) {
            message.error(error.response?.data?.message || 'Failed to delete task');
        }
    };

    const items = [
        {
            label: 'Status',
            children: (
                <Select
                    value={currentIssue.status}
                    onChange={v => handleUpdate('status', v)}
                    options={[
                        { value: 'todo', label: 'To Do' },
                        { value: 'in_progress', label: 'In Progress' },
                        { value: 'review', label: 'In Review' },
                        { value: 'done', label: 'Done' }
                    ]}
                    size="small"
                    style={{ width: 120 }}
                    disabled={loadingField === 'status'}
                />
            )
        },
        {
            label: 'Priority',
            children: (
                <Select
                    value={currentIssue.priority}
                    onChange={v => handleUpdate('priority', v)}
                    options={[
                        { value: 'low', label: '🟢 Low' },
                        { value: 'medium', label: '🟡 Medium' },
                        { value: 'high', label: '🟠 High' },
                        { value: 'critical', label: '🔴 Critical' }
                    ]}
                    size="small"
                    style={{ width: 120 }}
                    disabled={loadingField === 'priority'}
                />
            )
        },
        {
            label: 'Assignee',
            children: (
                <Select
                    mode="multiple"
                    value={currentIssue.assignedTo?.map(u => u._id || u) || []}
                    onChange={v => handleUpdate('assignedTo', v)}
                    style={{ width: '100%', minWidth: 150 }}
                    size="small"
                    placeholder="Unassigned"
                    optionFilterProp="label"
                    disabled={loadingField === 'assignedTo'}
                    loading={loadingField === 'assignedTo'}
                >
                    {users.map(u => (
                        <Select.Option key={u._id} value={u._id} label={u.fullName}>
                            <Space>
                                <Avatar size="small" style={{ backgroundColor: '#0052CC' }}>
                                    {u.fullName?.[0]}
                                </Avatar>
                                {u.fullName}
                            </Space>
                        </Select.Option>
                    ))}
                </Select>
            )
        },
        {
            label: 'Reporter',
            children: <Space>
                <Avatar size="small" style={{ backgroundColor: '#5E6C84' }}>
                    {currentIssue.reporter?.fullName?.[0]}
                </Avatar>
                {currentIssue.reporter?.fullName || 'Unknown'}
            </Space>
        },
        {
            label: 'Sprint',
            children: currentIssue.sprint?.name || 'Backlog'
        },
        {
            label: 'Story Points',
            children: (
                <Input
                    type="number"
                    style={{ width: 60 }}
                    value={currentIssue.storyPoints}
                    onChange={e => {
                        const val = e.target.value;
                        if (val && val !== String(currentIssue.storyPoints)) {
                            handleUpdate('storyPoints', parseInt(val) || 0);
                        }
                    }}
                    size="small"
                    disabled={loadingField === 'storyPoints'}
                />
            )
        },
        {
            label: 'Due Date',
            children: currentIssue.dueDate
                ? new Date(currentIssue.dueDate).toLocaleDateString()
                : <Text type="secondary">Not set</Text>
